class Solution {
public:
    string lastSubstring(string s) {
        int i = 0, j = 1, n = s.size();
        while (j < n) {
            int k = 0;
            while (j + k < n && s[i + k] == s[j + k]) k++;
            if (j + k < n && s[i + k] < s[j + k]) i = (i + k + 1 > j) ? j : i + k + 1;
            else j = j + k + 1;
        }
        return s.substr(i);
    }
};
